#include<bits/stdc++.h>
using namespace std;
long long dp1[100010],a[11],c[11],s,n;
long long dp(long long x)
{
    if(x<0)
    {
        return 0;
    }
    return dp1[x];
}
long long calc(long long A=0,long long B=0,long long C=0,long long D=0)
{
    if(A==0&&B==0&&C==0&&D==0)
    {
        return dp(s);
    }
    if(B==0&&C==0&&D==0)
    {
        return dp(s-c[A]*(a[A]+1));
    }
    if(C==0&&D==0)
    {
        return dp(s-c[A]*(a[A]+1)-c[B]*(a[B]+1));
    }
    if(D==0)
    {
        return dp(s-c[A]*(a[A]+1)-c[B]*(a[B]+1)-c[C]*(a[C]+1));
    }
    return dp(s-c[A]*(a[A]+1)-c[B]*(a[B]+1)-c[C]*(a[C]+1)-c[D]*(a[D]+1));
}
int main()
{
    scanf("%lld%lld%lld%lld%lld",&c[1],&c[2],&c[3],&c[4],&n);
    dp1[0]=1;
    for(long long i=1;i<=4;i++)
    {
        for(long long j=c[i];j<=100000;j++)
        {
            dp1[j]+=dp1[j-c[i]];
        }
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld%lld%lld%lld%lld",&a[1],&a[2],&a[3],&a[4],&s);
        long long ans=0;
        ans+=calc(1)+calc(2)+calc(3)+calc(4);
        ans-=calc(1,2)+calc(1,3)+calc(1,4)+calc(2,3)+calc(2,4)+calc(3,4);
        ans+=calc(1,2,3)+calc(1,2,4)+calc(1,3,4)+calc(2,3,4);
        ans-=calc(1,2,3,4);
        printf("%lld\n",dp(s)-ans);
    }
    return 0;
}
